INSERT INTO `v1_441d5356c1bc9986b1eef84abb7f12d05223a1f4682112e3dfff9fbff6cb1d86` VALUES ("vo_minigame_1013_icon_2_004_001", "すばらしい\n記録ですわ", 3, "vo_minigame_1013_icon_1_004_001", 3000, 10000, 3, 2, "へへっ、おまえら\nやるじゃねえか！", 2);
